export type AssetForEntities = {
    /**
     * The type of asset-to-entity mapping:
     *
     * * `NO_ENTITIES`: Not available to any entity.
     * * `ALL_ENTITIES`: Available to all entities.
     * * `FOLDER`: Available to all entities in a specified folder.
     * * `ENTITIES`: Available to entities with the IDs you specify.
     *
     */
    mappingType: string;
    /**
     * The *external* ID of the folder containing the entities this asset can be used for.
     *
     * Optional - can only be set if **`mappingType`** = `FOLDER`.
     *
     */
    folderId?: string;
    /**
     * The *external* IDs of the entities this asset can be used for.
     *
     * Optional - can only be set if **`mappingType`** = `ENTITIES`.
     *
     */
    entityIds?: Array<string>;
    /**
     * The *external* IDs of the labels given to the entities this asset can be used for.
     *
     * Note that these labels are NOT asset labels. They are entity labels associated with particular entities in the Knowledge Manager.
     *
     * Optional - can only be set if **`mappingType`** = `FOLDER` or `ALL_ENTITIES`.
     *
     */
    labelIds?: Array<string>;
    /**
     * The operator on the labels in **`labelIds`** (i.e., whether the asset can be used on entities with all (`AND`) or any (`OR`) of the labels specified).
     *
     * Optional - can only be set if **`mappingType`** = `FOLDER` or `ALL_ENTITIES`.
     *
     */
    labelOperator?: 'AND' | 'OR';
};

export type AssetUsage = {
    /**
     * The type of asset usage that is being defined. Can have one of the following values:
     *
     * * `ALL`
     * * `PROFILE_FIELDS`
     * * `REVIEW_RESPONSE`
     * * `SOCIAL_POSTING`
     * * `ALL_PROFILE_FIELDS`
     * * `REVIEW_RESPONSE_GREETING`
     * * `REVIEW_RESPONSE_VALUE_STATEMENT`
     * * `REVIEW_RESPONSE_POSITIVE_SENTIMENT`
     * * `REVIEW_RESPONSE_NEGATIVE_SENTIMENT`
     * * `REVIEW_RESPONSE_CLOSING`
     *
     * `ALL`
     * Indicates that the asset is available to services that use assets, including any that may be added in the future.
     *
     * `PROFILE_FIELDS`
     * Indicates that the asset is available to the fields specified in the **`fieldNames`** subfield.
     *
     * `REVIEW_RESPONSE`
     * Indicates that the asset can be used in responses to reviews.
     *
     * `SOCIAL_POSTING`
     * Indicates that the asset can be used in social posts.
     *
     * `ALL_PROFILE_FIELDS`
     * Indicates that the asset is available to all profile fields and any fields that may be added to the account in the future (e.g., custom fields).
     *
     * `REVIEW_RESPONSE_GREETING`
     * Indicates that the asset can be used as a greeting in Intelligent Review Responses.
     *
     * `REVIEW_RESPONSE_VALUE_STATEMENT`
     * Indicates that the asset can be used as a value statement in Intelligent Review Responses.
     *
     * `REVIEW_RESPONSE_POSITIVE_SENTIMENT`
     * Indicates that the asset can be used as a positive sentiment keyword in Intelligent Review Responses.
     *
     * `REVIEW_RESPONSE_NEGATIVE_SENTIMENT`
     * Indicates that the asset can be used as a negative sentiment keyword in Intelligent Review Responses.
     *
     * `REVIEW_RESPONSE_CLOSING`
     * Indicates that the asset can be used as closing remarks in Intelligent Review Responses.
     *
     */
    type?: string;
    /**
     * The names of the fields the asset is available to.
     *
     * Only applicable if **`usageType`** is `PROFILE_FIELDS`.
     *
     * A field's name in **`fieldNames`** matches its name in the API. For example, if an asset can be used for Business Name and Description, the **`fieldNames`** array will be:
     * `[“name”, “description”]`
     *
     * The **`fieldNames`** value for a custom field matches its **`name`**.
     *
     */
    fieldNames?: Array<string>;
};

